mapper.select:
SELECT uuvm.stb_ui_ver ,uuvm.ui_ver_expl ,uuvm.use_yn ,uuvm.stm_fir_reg_date ,uuvm.stm_fir_reg_user_id ,aum.user_nm ,(select count(*) from um_sw_file_dtl d where d.stb_ui_ver = uuvm.stb_ui_ver) cnt FROM dm_ui_ver_mst uuvm, ad_user_mst aum WHERE 1=1 AND uuvm.stm_fir_reg_user_id = user_id
AND uuvm.stb_ui_ver between #{fromUi} and #{toUi}
AND uuvm.stb_ui_ver = #{fromUi}
AND uuvm.stb_ui_ver >= #{fromUi}
AND uuvm.stb_ui_ver <= #{fromUi}
AND aum.user_id like '%'||#{stmFirRegUserId}||'%'
ORDER BY uuvm.stm_last_upd_date desc

mapper.update:
    UPDATE dm_ui_ver_mst
    SET
	    stb_ui_ver = #{stbUiVer}
      , ui_ver_expl = #{uiVerExpl}
      , use_yn = #{useYn}
      , stm_last_upd_date = SYSDATE
      , stm_last_upd_user_id = #{userId}
    WHERE stb_ui_ver = #{stbUiVer}

    
    UPDATE dm_ui_ver_mst
    SET del_yn = 'Y'
    WHERE stb_ui_ver = #{stbUiVer}

    UPDATE dm_ui_ver_map                                                                         
    SET
	  stb_ui_ver = #{stbUiVer}
      ,stb_ui_ver_expl = #{stbUiVerExpl}
      ,patch_dy = #{patchDy}
      ,stm_last_upd_date = sysdate
      ,stm_last_upd_user_id = #{stmLastUpdUserId}
    WHERE stb_full_ver = #{stbFullVer}
